class Solution:
    def makeStringsEqual(self, s: str, target: str) -> bool:
        for i in range(len(s)):
            for j in range(i+1, len(s)):
                if s[i] == target[i] and s[j] == target[j]:
                    s[i] ^= s[j]
                    s[j] ^= s[i]
                    if s == target:
                        return True
        return False
```

